        NOP
        NOP
        RST $38
        RST $38
        NOP
        NOP
        RST $38
        RST $38
        NOP
        NOP
        RST $38
        RST $38
        NOP
        NOP
        RST $38
        RST $38
        NOP
        NOP
        RST $38
        RST $38
        NOP
        NOP
